#!/usr/bin/env python3
"""kb-graph: Auto-generated knowledge graph for any repo.

Scans a git repo, discovers how all files connect via imports, wiki-links,
and config references, and produces KB_INDEX.md + graph.html.
"""

import argparse
import json
import os
import re
import subprocess
import sys
from collections import defaultdict
from datetime import datetime, timezone


# ── Constants ──────────────────────────────────────────────────────────────

IGNORE_DIRS = {
    ".git", "__pycache__", "node_modules", ".venv", "venv",
    "dist", "build", ".tox", ".mypy_cache", ".pytest_cache", "egg-info",
}

# Files generated by kb-graph — skip during scanning
IGNORE_FILES = {"KB_INDEX.md"}

CODE_EXTS = {".py"}
MD_EXTS = {".md"}
CONFIG_EXTS = {".yaml", ".yml", ".json", ".toml"}
SHELL_EXTS = {".sh", ".bash"}
R_EXTS = {".R"}
NF_EXTS = {".nf"}
ALL_TRACKED_EXTS = CODE_EXTS | MD_EXTS | CONFIG_EXTS | SHELL_EXTS | R_EXTS | NF_EXTS

PALETTE = [
    "#58a6ff", "#3fb950", "#d29922", "#f85149", "#bc8cff",
    "#f778ba", "#39d2c0", "#ff9a3c", "#56d364", "#e06c9f",
]


# ── File Discovery ─────────────────────────────────────────────────────────

def load_ignore_patterns(repo_root):
    """Load ignore patterns from .phoamignore and .gitignore."""
    patterns = []
    for filename in (".phoamignore", ".gitignore"):
        path = os.path.join(repo_root, filename)
        if os.path.isfile(path):
            with open(path, "r", errors="ignore") as f:
                for line in f:
                    line = line.strip()
                    if not line or line.startswith("#"):
                        continue
                    if line.startswith("!"):
                        continue  # negation not supported
                    patterns.append(line)
    return patterns


def matches_ignore(rel_path, patterns):
    """Check if a relative path matches any ignore pattern."""
    from fnmatch import fnmatch

    parts = rel_path.split("/")
    for pattern in patterns:
        # Directory pattern (ends with /)
        if pattern.endswith("/"):
            dir_name = pattern.rstrip("/")
            for part in parts[:-1]:  # check directory components
                if fnmatch(part, dir_name):
                    return True
            # Also check if the full relative directory path matches
            rel_dir = "/".join(parts[:-1])
            if rel_dir and (fnmatch(rel_dir, dir_name) or fnmatch(rel_dir + "/", pattern)):
                return True
        else:
            # File pattern
            basename = parts[-1]
            if fnmatch(basename, pattern):
                return True
            if fnmatch(rel_path, pattern):
                return True
    return False


def discover_files(repo_root):
    """Walk the repo and return tracked file paths (relative to repo_root)."""
    ignore_patterns = load_ignore_patterns(repo_root)
    tracked = []

    for dirpath, dirnames, filenames in os.walk(repo_root):
        # Filter out ignored directories in-place
        dirnames[:] = [
            d for d in dirnames
            if d not in IGNORE_DIRS
            and not matches_ignore(
                os.path.relpath(os.path.join(dirpath, d), repo_root) + "/",
                ignore_patterns,
            )
        ]

        for fname in filenames:
            full_path = os.path.join(dirpath, fname)
            rel_path = os.path.relpath(full_path, repo_root)

            # Normalize path separators
            rel_path = rel_path.replace(os.sep, "/")

            # Check extension
            _, ext = os.path.splitext(fname)
            if ext not in ALL_TRACKED_EXTS:
                continue

            # Skip generated files
            if fname in IGNORE_FILES:
                continue

            # Skip empty __init__.py
            if fname == "__init__.py":
                try:
                    if os.path.getsize(full_path) == 0:
                        continue
                except OSError:
                    continue

            # Check ignore patterns
            if matches_ignore(rel_path, ignore_patterns):
                continue

            tracked.append(rel_path)

    return sorted(tracked)


# ── Description Extraction ─────────────────────────────────────────────────

def get_description(filepath, repo_root):
    """Extract a short description from a file."""
    full_path = os.path.join(repo_root, filepath)
    ext = os.path.splitext(filepath)[1]

    try:
        with open(full_path, "r", errors="ignore") as f:
            content = f.read(4096)
    except OSError:
        return ""

    if ext == ".py":
        # Try module docstring (triple-quoted)
        m = re.match(
            r'^(?:\s*#[^\n]*\n)*\s*(?:"""(.*?)"""|\'\'\'(.*?)\'\'\')',
            content,
            re.DOTALL,
        )
        if m:
            doc = m.group(1) or m.group(2)
            return doc.strip().split("\n")[0].strip()
        # Fall back to first non-shebang comment
        for line in content.split("\n"):
            line = line.strip()
            if line.startswith("#!"):
                continue
            if line.startswith("#"):
                return line.lstrip("# ").strip()
            if line and not line.startswith("#"):
                break
        return ""

    elif ext == ".md":
        for line in content.split("\n"):
            line = line.strip()
            if line.startswith("# "):
                return line[2:].strip()
        return ""

    else:
        return ""


# ── Module Resolution ──────────────────────────────────────────────────────

def resolve_module(module_path, current_file, tracked_set):
    """Resolve a Python module path to a tracked file.

    Handles both absolute imports (core.config) and relative imports (.auth).
    Returns the resolved file path or None.
    """
    if module_path.startswith("."):
        # Relative import
        dots = len(module_path) - len(module_path.lstrip("."))
        rest = module_path[dots:]

        current_dir = os.path.dirname(current_file)
        for _ in range(dots - 1):
            current_dir = os.path.dirname(current_dir)

        if rest:
            candidate_base = (
                current_dir + "/" + rest.replace(".", "/") if current_dir else rest.replace(".", "/")
            )
        else:
            return None

        for suffix in (".py", "/__init__.py"):
            candidate = candidate_base + suffix
            if candidate in tracked_set:
                return candidate
        return None
    else:
        # Absolute import — convert dots to path separators
        file_path = module_path.replace(".", "/")

        # Try exact match first
        for suffix in (".py", "/__init__.py"):
            candidate = file_path + suffix
            if candidate in tracked_set:
                return candidate

        # Try suffix match (module relative to a source root like src/)
        for tracked in tracked_set:
            for suffix in (".py", "/__init__.py"):
                target = "/" + file_path + suffix
                if tracked.endswith(target):
                    return tracked

        return None


# ── Wiki-link Resolution ──────────────────────────────────────────────────

def resolve_wikilink(link_text, tracked_set):
    """Resolve a [[wiki-link]] to a tracked file path.

    Rules:
    1. If link contains '/' and has a file extension -> direct path
    2. Otherwise -> basename match (with or without extension)

    Returns (resolved_path, section) or (None, section).
    """
    section = None
    if "#" in link_text:
        link_text, section = link_text.split("#", 1)

    # Strip display text (pipe syntax: [[file|display]])
    if "|" in link_text:
        link_text = link_text.split("|")[0]

    link_text = link_text.strip()
    if not link_text:
        return None, section

    # Direct path reference (contains / and has extension)
    if "/" in link_text and "." in link_text.split("/")[-1]:
        if link_text in tracked_set:
            return link_text, section
        return None, section

    # Basename matching
    has_ext = "." in link_text
    matches = []

    for f in tracked_set:
        basename = os.path.basename(f)
        stem = os.path.splitext(basename)[0]

        if has_ext:
            if basename == link_text:
                matches.append(f)
        else:
            if stem == link_text:
                matches.append(f)

    if len(matches) == 1:
        return matches[0], section
    elif len(matches) > 1:
        # Ambiguous — return first match, could warn
        return matches[0], section

    return None, section


# ── Parsers ────────────────────────────────────────────────────────────────

def parse_python(filepath, repo_root, tracked_set):
    """Parse a Python file for imports and Design wiki-links."""
    edges = []
    full_path = os.path.join(repo_root, filepath)

    try:
        with open(full_path, "r", errors="ignore") as f:
            content = f.read()
    except OSError:
        return edges

    seen_targets = set()

    for line in content.split("\n"):
        stripped = line.strip()

        # Check for # Design: [[link]] comments anywhere in the line
        wl_match = re.search(r"#\s*Design:\s*\[\[(.+?)\]\]", stripped)
        if wl_match:
            target, section = resolve_wikilink(wl_match.group(1), tracked_set)
            if target and target != filepath and target not in seen_targets:
                seen_targets.add(target)
                edges.append({
                    "from": filepath, "to": target,
                    "type": "wiki-link", "section": section,
                })

        # Skip pure comment lines for import parsing
        if stripped.startswith("#") or not stripped:
            continue

        # from .X import Y (relative import)
        m = re.match(r"^from\s+(\.+[\w.]*)\s+import\s+(.+)", stripped)
        if m:
            module_base = m.group(1)
            names_str = m.group(2).split("#")[0]  # strip inline comments
            names = [n.strip().split()[0].strip(",") for n in names_str.split(",")]

            resolved_set = set()
            for name in names:
                if name == "*" or not name:
                    continue
                # For relative imports, try module_base.name as submodule
                dots = len(module_base) - len(module_base.lstrip("."))
                rest = module_base[dots:]
                if rest:
                    full_module = module_base + "." + name
                else:
                    full_module = "." * dots + name
                resolved = resolve_module(full_module, filepath, tracked_set)
                if resolved and resolved != filepath:
                    resolved_set.add(resolved)

            # If no submodules resolved, try the base module
            if not resolved_set:
                resolved = resolve_module(module_base, filepath, tracked_set)
                if resolved and resolved != filepath:
                    resolved_set.add(resolved)

            for target in resolved_set:
                if target not in seen_targets:
                    seen_targets.add(target)
                    edges.append({
                        "from": filepath, "to": target,
                        "type": "import", "section": None,
                    })
            continue

        # from X.Y import Z (absolute import)
        m = re.match(r"^from\s+([\w.]+)\s+import\s+(.+)", stripped)
        if m:
            module_base = m.group(1)
            names_str = m.group(2).split("#")[0]
            names = [n.strip().split()[0].strip(",") for n in names_str.split(",")]

            resolved_set = set()
            for name in names:
                if name == "*" or not name:
                    continue
                full_module = module_base + "." + name
                resolved = resolve_module(full_module, filepath, tracked_set)
                if resolved and resolved != filepath:
                    resolved_set.add(resolved)

            if not resolved_set:
                resolved = resolve_module(module_base, filepath, tracked_set)
                if resolved and resolved != filepath:
                    resolved_set.add(resolved)

            for target in resolved_set:
                if target not in seen_targets:
                    seen_targets.add(target)
                    edges.append({
                        "from": filepath, "to": target,
                        "type": "import", "section": None,
                    })
            continue

        # import X.Y.Z
        m = re.match(r"^import\s+([\w.]+)", stripped)
        if m:
            module = m.group(1)
            resolved = resolve_module(module, filepath, tracked_set)
            if resolved and resolved != filepath and resolved not in seen_targets:
                seen_targets.add(resolved)
                edges.append({
                    "from": filepath, "to": resolved,
                    "type": "import", "section": None,
                })
            continue

    return edges


def extract_exports(filepath):
    """Extract top-level function signatures and class definitions from a Python file.

    Returns a list of strings like:
        "apply_transform(data: DataFrame, config: Config, strict: bool = True) -> DataFrame"
        "class TransformConfig"
        "class PipelineError(Exception)"

    Skips private functions (_prefixed), nested functions, and methods inside classes.
    Handles multiline signatures (parentheses spanning multiple lines).
    """
    try:
        with open(filepath, "r", errors="ignore") as f:
            lines = f.readlines()
    except OSError:
        return []

    exports = []
    indent_in_class = False  # True when we're inside a class body
    i = 0

    while i < len(lines):
        line = lines[i]
        stripped = line.rstrip()
        leading_spaces = len(line) - len(line.lstrip())

        # Track whether we're inside a class body (indented)
        if stripped and not stripped.startswith("#"):
            if leading_spaces == 0:
                indent_in_class = False

        # Top-level class definition
        if leading_spaces == 0 and re.match(r"^class\s+", stripped):
            m = re.match(r"^class\s+(\w+)(?:\(([^)]*)\))?\s*:", stripped)
            if m:
                name = m.group(1)
                bases = m.group(2)
                if bases:
                    exports.append(f"class {name}({bases.strip()})")
                else:
                    exports.append(f"class {name}")
                indent_in_class = True
            i += 1
            continue

        # Top-level function definition (not inside a class, not private)
        if leading_spaces == 0 and re.match(r"^def\s+", stripped) and not indent_in_class:
            m = re.match(r"^def\s+(\w+)\s*\(", stripped)
            if m:
                name = m.group(1)
                # Skip private functions
                if name.startswith("_"):
                    i += 1
                    continue

                # Collect the full signature (may span multiple lines)
                sig_lines = [stripped]
                # Check if parentheses are balanced
                paren_depth = stripped.count("(") - stripped.count(")")
                j = i + 1
                while paren_depth > 0 and j < len(lines):
                    sig_lines.append(lines[j].rstrip())
                    paren_depth += lines[j].count("(") - lines[j].count(")")
                    j += 1

                full_sig = " ".join(s.strip() for s in sig_lines)

                # Extract: def name(params) -> return_type:
                sig_match = re.match(
                    r"def\s+(\w+)\s*\(([^)]*)\)\s*(?:->\s*(.+?))?\s*:",
                    full_sig,
                )
                if sig_match:
                    func_name = sig_match.group(1)
                    params_raw = sig_match.group(2)
                    return_type = sig_match.group(3)

                    # Clean up params: collapse whitespace, strip trailing commas
                    params = ", ".join(
                        p.strip() for p in params_raw.split(",") if p.strip()
                    )

                    if return_type:
                        exports.append(f"{func_name}({params}) -> {return_type.strip()}")
                    else:
                        exports.append(f"{func_name}({params})")

            i += 1
            continue

        # Inside a class body — skip methods (they're indented)
        if leading_spaces > 0 and indent_in_class and re.match(r"\s+def\s+", line):
            i += 1
            continue

        i += 1

    return exports


def parse_markdown(filepath, repo_root, tracked_set):
    """Parse a Markdown file for [[wiki-links]]."""
    edges = []
    full_path = os.path.join(repo_root, filepath)

    try:
        with open(full_path, "r", errors="ignore") as f:
            content = f.read()
    except OSError:
        return edges

    seen_targets = set()

    for match in re.finditer(r"\[\[(.+?)\]\]", content):
        link_text = match.group(1)
        target, section = resolve_wikilink(link_text, tracked_set)
        if target and target != filepath and target not in seen_targets:
            seen_targets.add(target)
            edges.append({
                "from": filepath, "to": target,
                "type": "wiki-link", "section": section,
            })

    return edges


def parse_config(filepath, repo_root, tracked_set):
    """Parse a config file for file path references."""
    edges = []
    full_path = os.path.join(repo_root, filepath)
    ext = os.path.splitext(filepath)[1]

    try:
        with open(full_path, "r", errors="ignore") as f:
            content = f.read()
    except OSError:
        return edges

    # Extract string values
    values = set()

    if ext == ".json":
        try:
            data = json.loads(content)
            _extract_json_strings(data, values)
        except (json.JSONDecodeError, ValueError):
            pass
    else:
        # YAML / TOML — extract quoted strings
        for m in re.finditer(r'''["']([^"']+)["']''', content):
            values.add(m.group(1).strip())
        # Also unquoted values that look like file paths
        for m in re.finditer(
            r":\s*(\S+\.(?:py|md|yaml|yml|json|toml|sh|R|nf))\s*$",
            content,
            re.MULTILINE,
        ):
            values.add(m.group(1).strip())

    seen_targets = set()
    for value in values:
        if value in tracked_set and value != filepath and value not in seen_targets:
            seen_targets.add(value)
            edges.append({
                "from": filepath, "to": value,
                "type": "config-ref", "section": None,
            })

    return edges


def _extract_json_strings(obj, result):
    """Recursively extract all string values from a JSON object."""
    if isinstance(obj, str):
        result.add(obj)
    elif isinstance(obj, dict):
        for v in obj.values():
            _extract_json_strings(v, result)
    elif isinstance(obj, list):
        for item in obj:
            _extract_json_strings(item, result)


# ── Graph Building ─────────────────────────────────────────────────────────

def get_group(filepath):
    """Determine the component group for a file.

    Used for KB_INDEX.md section headers and graph.html node colors.
    """
    parts = filepath.split("/")
    if len(parts) == 1:
        return "root"
    if parts[0] == "src":
        if len(parts) == 2:
            return "src"
        return "src/" + parts[1]
    return parts[0]


def get_file_type(filepath):
    """Determine the file type (code, doc, config)."""
    ext = os.path.splitext(filepath)[1]
    if ext in CODE_EXTS:
        return "code"
    if ext in MD_EXTS:
        return "doc"
    if ext in CONFIG_EXTS:
        return "config"
    return "asset"


PARSER_MAP = {
    ".py": parse_python,
    ".md": parse_markdown,
    ".yaml": parse_config,
    ".yml": parse_config,
    ".json": parse_config,
    ".toml": parse_config,
}


def build_graph(repo_root):
    """Scan the repo and build the full dependency graph."""
    repo_root = os.path.abspath(repo_root)
    tracked_files = discover_files(repo_root)
    tracked_set = set(tracked_files)

    nodes = {}
    edges = []

    # Build nodes
    for filepath in tracked_files:
        nodes[filepath] = {
            "description": get_description(filepath, repo_root),
            "group": get_group(filepath),
            "type": get_file_type(filepath),
        }

    # Parse edges
    for filepath in tracked_files:
        ext = os.path.splitext(filepath)[1]
        parser = PARSER_MAP.get(ext)
        if parser:
            file_edges = parser(filepath, repo_root, tracked_set)
            edges.extend(file_edges)

    # Deduplicate edges
    seen = set()
    unique_edges = []
    for edge in edges:
        key = (edge["from"], edge["to"], edge["type"])
        if key not in seen:
            seen.add(key)
            unique_edges.append(edge)

    return {"nodes": nodes, "edges": unique_edges}


# ── Display Names ──────────────────────────────────────────────────────────

def get_display_name(filepath, from_path=None):
    """Get a human-readable display name for a file.

    If from_path is given and both files share the same directory,
    use relative notation (e.g., '.auth').
    """
    stem = os.path.splitext(os.path.basename(filepath))[0]

    if from_path:
        from_dir = os.path.dirname(from_path)
        to_dir = os.path.dirname(filepath)
        if from_dir == to_dir:
            return "." + stem

    # Strip src/ prefix and convert to module notation
    path = filepath
    if path.startswith("src/"):
        path = path[4:]
    mod_path = os.path.splitext(path)[0].replace("/", ".")
    return mod_path


# ── Output: KB_INDEX.md ───────────────────────────────────────────────────

def write_kb_index(graph, repo_root):
    """Generate KB_INDEX.md from the graph."""
    nodes = graph["nodes"]
    edges = graph["edges"]

    # Compute inbound and outbound edges per node
    outbound = defaultdict(list)  # node -> list of (target, edge)
    inbound = defaultdict(list)   # node -> list of (source, edge)
    for edge in edges:
        outbound[edge["from"]].append(edge)
        inbound[edge["to"]].append(edge)

    # Find orphans (no inbound or outbound edges)
    orphan_nodes = []
    connected_nodes = {}
    for path, meta in sorted(nodes.items()):
        if not outbound[path] and not inbound[path]:
            orphan_nodes.append(path)
        else:
            connected_nodes[path] = meta

    # Group connected nodes
    groups = defaultdict(list)
    for path, meta in sorted(connected_nodes.items()):
        groups[meta["group"]].append(path)

    # Stats
    now = datetime.now(timezone.utc).strftime("%Y-%m-%d %H:%M:%S UTC")
    node_count = len(nodes)
    edge_count = len(edges)
    orphan_count = len(orphan_nodes)

    lines = []
    lines.append("# KB_INDEX.md")
    lines.append(
        f"> Auto-generated by kb-graph — do not edit manually.\n"
        f"> Last rebuilt: {now} | Nodes: {node_count} | Edges: {edge_count} | Orphans: {orphan_count}"
    )
    lines.append("")
    lines.append("---")
    lines.append("")

    # Write each group
    for group_name in sorted(groups.keys()):
        lines.append(f"## {group_name}")
        lines.append("")

        for filepath in groups[group_name]:
            meta = nodes[filepath]
            basename = os.path.basename(filepath)
            desc = meta["description"]

            # Build the node entry
            if desc:
                lines.append(f"- **{basename}** — {desc}")
            else:
                lines.append(f"- **{basename}**")

            file_type = meta["type"]

            if file_type == "code":
                # Imports (outbound import edges)
                import_edges = [e for e in outbound[filepath] if e["type"] == "import"]
                if import_edges:
                    import_names = [
                        f"`{get_display_name(e['to'], filepath)}`"
                        for e in import_edges
                    ]
                    lines.append(f"  - imports: {', '.join(import_names)}")

                # Used by (inbound import edges)
                used_by_edges = [e for e in inbound[filepath] if e["type"] == "import"]
                if used_by_edges:
                    if len(used_by_edges) >= 5:
                        lines.append(f"  - used by {len(used_by_edges)} modules")
                    else:
                        used_names = [
                            f"`{get_display_name(e['from'], filepath)}`"
                            for e in used_by_edges
                        ]
                        lines.append(f"  - used by: {', '.join(used_names)}")

                # Doc links (inbound wiki-link edges from docs)
                doc_links = [
                    e for e in inbound[filepath]
                    if e["type"] == "wiki-link" and nodes.get(e["from"], {}).get("type") == "doc"
                ]
                if doc_links:
                    doc_names = []
                    for e in doc_links:
                        stem = os.path.splitext(os.path.basename(e["from"]))[0]
                        if e.get("section"):
                            doc_names.append(f"[[{stem}#{e['section']}]]")
                        else:
                            doc_names.append(f"[[{stem}]]")
                    lines.append(f"  - docs: {', '.join(doc_names)}")

            elif file_type == "doc":
                # Links to (outbound wiki-link edges)
                link_edges = [e for e in outbound[filepath] if e["type"] == "wiki-link"]
                if link_edges:
                    link_names = []
                    for e in link_edges:
                        stem = os.path.splitext(os.path.basename(e["to"]))[0]
                        ext = os.path.splitext(e["to"])[1]
                        if ext in CODE_EXTS:
                            link_names.append(f"[[{os.path.basename(e['to'])}]]")
                        else:
                            link_names.append(f"[[{stem}]]")
                    lines.append(f"  - links to: {', '.join(link_names)}")

            elif file_type == "config":
                # Config refs (outbound config-ref edges)
                ref_edges = [e for e in outbound[filepath] if e["type"] == "config-ref"]
                if ref_edges:
                    ref_names = [f"`{e['to']}`" for e in ref_edges]
                    lines.append(f"  - references: {', '.join(ref_names)}")

            lines.append("")

    # Orphans section
    if orphan_nodes:
        lines.append("## Orphans")
        lines.append("")
        for filepath in sorted(orphan_nodes):
            meta = nodes[filepath]
            desc = meta["description"]
            basename = os.path.basename(filepath)
            if desc:
                lines.append(f"- **{basename}** — {desc} (no connections)")
            else:
                lines.append(f"- **{basename}** — no connections")
            lines.append("")

    output = "\n".join(lines).rstrip() + "\n"
    output_path = os.path.join(repo_root, "KB_INDEX.md")
    with open(output_path, "w") as f:
        f.write(output)

    return output_path


