def write_graph_html(graph, repo_root):
    """Generate graph.html from the graph data."""
    nodes = graph["nodes"]
    edges = graph["edges"]

    # Compute degree per node
    degree = defaultdict(int)
    for edge in edges:
        degree[edge["from"]] += 1
        degree[edge["to"]] += 1

    # Build groups list
    group_names = sorted(set(meta["group"] for meta in nodes.values()))
    groups_data = [
        {"name": g, "color": PALETTE[i % len(PALETTE)]}
        for i, g in enumerate(group_names)
    ]

    # Build nodes data
    nodes_data = []
    for path, meta in sorted(nodes.items()):
        d = degree[path]
        radius = max(5, min(20, 5 + d * 2))
        nodes_data.append({
            "id": path,
            "label": os.path.basename(path),
            "group": meta["group"],
            "description": meta["description"],
            "type": meta["type"],
            "degree": d,
            "radius": radius,
        })

    # Build links data
    links_data = [
        {"source": e["from"], "target": e["to"], "type": e["type"]}
        for e in edges
    ]

    # Orphan count
    connected = set()
    for e in edges:
        connected.add(e["from"])
        connected.add(e["to"])
    orphan_count = sum(1 for path in nodes if path not in connected)

    graph_json = json.dumps({
        "nodes": nodes_data,
        "links": links_data,
        "groups": groups_data,
        "stats": {
            "nodes": len(nodes),
            "edges": len(edges),
            "orphans": orphan_count,
        },
    }, indent=2)

    html = GRAPH_HTML_TEMPLATE.replace("%%GRAPH_DATA%%", graph_json)

    output_path = os.path.join(repo_root, "graph.html")
    with open(output_path, "w") as f:
        f.write(html)

    return output_path


